// Normalize title for deduplication
function normalizeTitle(title) {
  return title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9-]/g, '-')
    .replace(/-+/g, '-')
    .replace(/-$/, '');
}

// Infer category from content
function inferCategory(article) {
  const text = `${article.title || ''} ${article.content || ''}`.toLowerCase();

  if (['test', 'testing', 'qa', 'automation', 'cypress', 'playwright', 'selenium'].some(w => text.includes(w))) {
    return 'test-automation';
  }
  if (['ai', 'llm', 'gpt', 'claude', 'agent', 'prompt', 'generative'].some(w => text.includes(w))) {
    return 'ai';
  }
  if (['architecture', 'deploy', 'performance', 'scaling', 'infrastructure', 'kubernetes'].some(w => text.includes(w))) {
    return 'engineering';
  }
  if (['tool', 'script', 'library', 'framework', 'npm', 'package'].some(w => text.includes(w))) {
    return 'tooling';
  }

  return 'qa-practice';
}

// Generate UUID-like ID (simplified for n8n)
function generateId() {
  return 'article-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
}

const article = $json;

return {
  json: {
    // Existing fields from M3
    ...article,

    // Generated/transformed fields for Knowledge Layer
    id: article.id || generateId(),
    title: article.title || 'Untitled',
    summary: (article.content || article.contentSnippet || '').substring(0, 1000),
    url: article.url || article.link || '',
    source: article.source || article.feed?.title || 'Unknown',
    category: article.category || inferCategory(article),
    publishedAt: article.published_at || article.isoDate || article.pubDate || new Date().toISOString(),
    tags: Array.isArray(article.tags) ? article.tags.join(',') : (article.tags || ''),
    addedAt: new Date().toISOString(),
    score: article.score || 50,
    seenCount: 1,
    dedupKey: (article.source || 'Unknown') + '|' + normalizeTitle(article.title || 'untitled')
  }
};

// Check if article was found in last 30 days
const isDuplicate = $input.all().length > 0;
const existingRow = isDuplicate ? $input.all()[0] : null;

return {
  json: {
    isDuplicate: isDuplicate,
    existingId: existingRow?.id || null,
    existingSeenCount: existingRow?.seenCount || 0,
    existingScore: existingRow?.score || null
  }
};

// For UPDATE path: increment seenCount and update score
const article = $json;
const isDuplicate = $json.isDuplicate;

if (!isDuplicate) {
  return null; // Skip for new articles
}

return {
  json: {
    existingId: article.existingId,
    newSeenCount: (article.existingSeenCount || 0) + 1,
    newScore: Math.max(article.existingScore || 0, article.score || 50)
  }
};

// For INSERT path: prepare new article
const article = $json;
const isDuplicate = $json.isDuplicate;

if (isDuplicate) {
  return null; // Skip for duplicates
}

return article;

// Log result (INSERT or UPDATE)
const article = $json;
const operation = article.existingId ? 'updated' : 'inserted';
const title = article.title || article.newTitle || 'Unknown';
const source = article.source || 'Unknown';

return {
  json: {
    status: operation,
    operation: operation === 'updated' ? 'updated (seenCount++, score adjusted)' : 'inserted (new)',
    id: article.id || article.existingId,
    title: title,
    source: source,
    dedupKey: article.dedupKey,
    score: article.score || article.newScore
  }
};
